const data = $('Fetch Market Data').first().json;

if (!data) {
  throw new Error('No data found from HTTP Request node — check the connection and pinned data.');
}

const id = data.id;
const zipCode = data.zipCode;

const saleHistory = data.saleData?.history || {};
const rentHistory = data.rentalData?.history || {};

const saleMonths = Object.keys(saleHistory).sort();
const rentMonths = Object.keys(rentHistory).sort();

const last3Sale = saleMonths.slice(-3);
const last3Rent = rentMonths.slice(-3);

function compare(historyObj, months, field) {
  const series = months.map(m => ({
    month: m,
    value: historyObj[m]?.[field] ?? null
  }));

  while (series.length < 3) series.unshift({ month: null, value: null });

  const [twoAgo, oneAgo, current] = series;

  const diff = (current?.value != null && oneAgo?.value != null)
    ? current.value - oneAgo.value
    : null;

  const pct = (diff != null && oneAgo.value !== 0)
    ? (diff / oneAgo.value) * 100
    : null;

  return {
    months: series,
    previousMonth: oneAgo,
    currentMonth: current,
    change: diff !== null ? Number(diff.toFixed(2)) : null,
    percentChange: pct !== null ? Number(pct.toFixed(2)) : null,
    direction: diff > 0 ? 'increase' : diff < 0 ? 'decrease' : diff === 0 ? 'no change' : 'insufficient data'
  };
}

// Plain-English sentence for one metric (price or rent)
function buildSentence(comparison, label, currency = true) {
  const { previousMonth, currentMonth, change, percentChange, direction } = comparison;

  if (!previousMonth?.month || !currentMonth?.month || change === null) {
    return `Not enough historical data to compare ${label.toLowerCase()} month-over-month.`;
  }

  const fmt = (v) => currency
    ? `$${Math.abs(v).toLocaleString(undefined, { maximumFractionDigits: 0 })}`
    : Math.abs(v).toLocaleString();

  const curVal = fmt(currentMonth.value);
  const prevVal = fmt(previousMonth.value);
  const changeVal = fmt(change);
  const pctVal = percentChange !== null ? `${Math.abs(percentChange)}%` : 'an unknown percentage';

  if (direction === 'no change') {
    return `${label} stayed flat at ${curVal} in ${currentMonth.month}, unchanged from ${previousMonth.month}.`;
  }

  return `${label} in ${currentMonth.month} is ${curVal}, ${direction === 'increase' ? 'up' : 'down'} ${changeVal} (${pctVal}) from ${prevVal} in ${previousMonth.month}.`;
}

// Slack mrkdwn version of the same metric — bold values, arrow + emoji for direction
function buildSlackLine(comparison, label, currency = true) {
  const { previousMonth, currentMonth, change, percentChange, direction } = comparison;

  if (!previousMonth?.month || !currentMonth?.month || change === null) {
    return `:warning: *${label}*: not enough historical data to compare month-over-month.`;
  }

  const fmt = (v) => currency
    ? `$${Math.abs(v).toLocaleString(undefined, { maximumFractionDigits: 0 })}`
    : Math.abs(v).toLocaleString();

  const curVal = fmt(currentMonth.value);
  const prevVal = fmt(previousMonth.value);
  const changeVal = fmt(change);
  const pctVal = percentChange !== null ? `${Math.abs(percentChange)}%` : 'n/a';

  const arrow = direction === 'increase' ? ':arrow_upper_right:' : direction === 'decrease' ? ':arrow_lower_right:' : ':heavy_minus_sign:';
  const verb = direction === 'increase' ? 'up' : direction === 'decrease' ? 'down' : 'flat';

  return `${arrow} *${label}*: *${curVal}* (${currentMonth.month}) — ${verb} ${changeVal} (*${pctVal}*) vs ${prevVal} in ${previousMonth.month}`;
}

const saleComparison = compare(saleHistory, last3Sale, 'averagePrice');
const rentComparison = compare(rentHistory, last3Rent, 'averageRent');

const saleSentence = buildSentence(saleComparison, 'Average sale price', true);
const rentSentence = buildSentence(rentComparison, 'Average rent', true);

const saleSlackLine = buildSlackLine(saleComparison, 'Avg Sale Price', true);
const rentSlackLine = buildSlackLine(rentComparison, 'Avg Rent', true);

// Flag: true only if BOTH sale and rent have real month-over-month comparisons
const hasSufficientData =
  saleComparison.change !== null &&
  rentComparison.change !== null &&
  saleComparison.previousMonth?.month != null &&
  saleComparison.currentMonth?.month != null &&
  rentComparison.previousMonth?.month != null &&
  rentComparison.currentMonth?.month != null;

const slackSummary = `*Market Update — ZIP ${zipCode}*\n${saleSlackLine}\n${rentSlackLine}`;

return [{
  json: {
    id,
    zipCode,
    sale: saleComparison,
    rent: rentComparison,
    summary: `${saleSentence} ${rentSentence}`,
    slackSummary,
    hasSufficientData
  }
}];

